DO $$
BEGIN
  IF EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'alerts' AND column_name = 'speedLimit')
      AND NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'alerts' AND column_name = 'speedlimit') THEN
    ALTER TABLE alerts RENAME COLUMN "speedLimit" TO speedlimit;
  END IF;

  IF EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'alert_devices' AND column_name = 'alertId')
      AND NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'alert_devices' AND column_name = 'alertid') THEN
    ALTER TABLE alert_devices RENAME COLUMN "alertId" TO alertid;
  END IF;
  IF EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'alert_devices' AND column_name = 'deviceId')
      AND NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'alert_devices' AND column_name = 'deviceid') THEN
    ALTER TABLE alert_devices RENAME COLUMN "deviceId" TO deviceid;
  END IF;

  IF EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'alert_vehicle_groups' AND column_name = 'alertId')
      AND NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'alert_vehicle_groups' AND column_name = 'alertid') THEN
    ALTER TABLE alert_vehicle_groups RENAME COLUMN "alertId" TO alertid;
  END IF;
  IF EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'alert_vehicle_groups' AND column_name = 'groupId')
      AND NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'alert_vehicle_groups' AND column_name = 'groupid') THEN
    ALTER TABLE alert_vehicle_groups RENAME COLUMN "groupId" TO groupid;
  END IF;

  IF EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'alert_geofences' AND column_name = 'alertId')
      AND NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'alert_geofences' AND column_name = 'alertid') THEN
    ALTER TABLE alert_geofences RENAME COLUMN "alertId" TO alertid;
  END IF;
  IF EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'alert_geofences' AND column_name = 'geofenceId')
      AND NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'alert_geofences' AND column_name = 'geofenceid') THEN
    ALTER TABLE alert_geofences RENAME COLUMN "geofenceId" TO geofenceid;
  END IF;

  IF EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'alert_geofence_groups' AND column_name = 'alertId')
      AND NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'alert_geofence_groups' AND column_name = 'alertid') THEN
    ALTER TABLE alert_geofence_groups RENAME COLUMN "alertId" TO alertid;
  END IF;
  IF EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'alert_geofence_groups' AND column_name = 'geofenceGroupId')
      AND NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'alert_geofence_groups' AND column_name = 'geofencegroupid') THEN
    ALTER TABLE alert_geofence_groups RENAME COLUMN "geofenceGroupId" TO geofencegroupid;
  END IF;

  IF EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'alert_logs' AND column_name = 'alertId')
      AND NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'alert_logs' AND column_name = 'alertid') THEN
    ALTER TABLE alert_logs RENAME COLUMN "alertId" TO alertid;
  END IF;
  IF EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'alert_logs' AND column_name = 'vehicleGroup')
      AND NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'alert_logs' AND column_name = 'vehiclegroup') THEN
    ALTER TABLE alert_logs RENAME COLUMN "vehicleGroup" TO vehiclegroup;
  END IF;
  IF EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'alert_logs' AND column_name = 'geofenceName')
      AND NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'alert_logs' AND column_name = 'geofencename') THEN
    ALTER TABLE alert_logs RENAME COLUMN "geofenceName" TO geofencename;
  END IF;
  IF EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'alert_logs' AND column_name = 'alertName')
      AND NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'alert_logs' AND column_name = 'alertname') THEN
    ALTER TABLE alert_logs RENAME COLUMN "alertName" TO alertname;
  END IF;
  IF EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'alert_logs' AND column_name = 'recordedSpeed')
      AND NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'alert_logs' AND column_name = 'recordedspeed') THEN
    ALTER TABLE alert_logs RENAME COLUMN "recordedSpeed" TO recordedspeed;
  END IF;
  IF EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'alert_logs' AND column_name = 'eventTime')
      AND NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'alert_logs' AND column_name = 'eventtime') THEN
    ALTER TABLE alert_logs RENAME COLUMN "eventTime" TO eventtime;
  END IF;
END $$;

DO $$
BEGIN
  IF NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'tc_alerts' AND column_name = 'description') THEN
    ALTER TABLE tc_alerts ADD COLUMN description VARCHAR(4000);
  END IF;
  IF NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'tc_alerts' AND column_name = 'severity') THEN
    ALTER TABLE tc_alerts ADD COLUMN severity VARCHAR(32) DEFAULT 'medium';
  END IF;
  IF NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'tc_alerts' AND column_name = 'limitvalue') THEN
    ALTER TABLE tc_alerts ADD COLUMN limitvalue DOUBLE PRECISION;
  END IF;
  IF EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'tc_alerts' AND column_name = 'speedlimit') THEN
    UPDATE tc_alerts SET limitvalue = speedlimit WHERE limitvalue IS NULL;
    ALTER TABLE tc_alerts ALTER COLUMN speedlimit DROP NOT NULL;
  END IF;
  IF NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'tc_alerts' AND column_name = 'unit') THEN
    ALTER TABLE tc_alerts ADD COLUMN unit VARCHAR(32);
  END IF;
  IF NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'tc_alerts' AND column_name = 'operator') THEN
    ALTER TABLE tc_alerts ADD COLUMN operator VARCHAR(16);
  END IF;
  IF NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'tc_alerts' AND column_name = 'createdby') THEN
    ALTER TABLE tc_alerts ADD COLUMN createdby INT;
  END IF;
  IF NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'tc_alerts' AND column_name = 'createdat') THEN
    ALTER TABLE tc_alerts ADD COLUMN createdat TIMESTAMP;
  END IF;
  IF NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'tc_alerts' AND column_name = 'updatedat') THEN
    ALTER TABLE tc_alerts ADD COLUMN updatedat TIMESTAMP;
  END IF;
  IF NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'tc_alerts' AND column_name = 'attributes') THEN
    ALTER TABLE tc_alerts ADD COLUMN attributes VARCHAR(4000);
  END IF;
END $$;

DO $$
BEGIN
  IF NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'tc_alert_devices' AND column_name = 'groupid') THEN
    ALTER TABLE tc_alert_devices ADD COLUMN groupid INT;
  END IF;
  IF EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'tc_alert_devices' AND column_name = 'deviceid') THEN
    ALTER TABLE tc_alert_devices ALTER COLUMN deviceid DROP NOT NULL;
  END IF;

  IF NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'tc_alert_geofences' AND column_name = 'groupid') THEN
    ALTER TABLE tc_alert_geofences ADD COLUMN groupid INT;
  END IF;
  IF EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'tc_alert_geofences' AND column_name = 'geofenceid') THEN
    ALTER TABLE tc_alert_geofences ALTER COLUMN geofenceid DROP NOT NULL;
  END IF;
END $$;

DO $$
BEGIN
  IF NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'tc_alert_events' AND column_name = 'deviceid') THEN
    ALTER TABLE tc_alert_events ADD COLUMN deviceid INT;
  END IF;
  IF NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'tc_alert_events' AND column_name = 'positionid') THEN
    ALTER TABLE tc_alert_events ADD COLUMN positionid INT;
  END IF;
  IF NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'tc_alert_events' AND column_name = 'type') THEN
    ALTER TABLE tc_alert_events ADD COLUMN type VARCHAR(32);
  END IF;
  IF NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'tc_alert_events' AND column_name = 'severity') THEN
    ALTER TABLE tc_alert_events ADD COLUMN severity VARCHAR(32);
  END IF;
  IF NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'tc_alert_events' AND column_name = 'status') THEN
    ALTER TABLE tc_alert_events ADD COLUMN status VARCHAR(32) DEFAULT 'open';
  END IF;
  UPDATE tc_alert_events SET status = 'open' WHERE status IS NULL;
  IF NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'tc_alert_events' AND column_name = 'acknowledgedat') THEN
    ALTER TABLE tc_alert_events ADD COLUMN acknowledgedat TIMESTAMP;
  END IF;
  IF NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'tc_alert_events' AND column_name = 'acknowledgedby') THEN
    ALTER TABLE tc_alert_events ADD COLUMN acknowledgedby INT;
  END IF;
  IF NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'tc_alert_events' AND column_name = 'resolvedat') THEN
    ALTER TABLE tc_alert_events ADD COLUMN resolvedat TIMESTAMP;
  END IF;
  IF NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'tc_alert_events' AND column_name = 'message') THEN
    ALTER TABLE tc_alert_events ADD COLUMN message VARCHAR(4000);
  END IF;
  IF NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'tc_alert_events' AND column_name = 'value') THEN
    ALTER TABLE tc_alert_events ADD COLUMN value DOUBLE PRECISION;
  END IF;
  IF NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'tc_alert_events' AND column_name = 'threshold') THEN
    ALTER TABLE tc_alert_events ADD COLUMN threshold DOUBLE PRECISION;
  END IF;
  IF NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'tc_alert_events' AND column_name = 'unit') THEN
    ALTER TABLE tc_alert_events ADD COLUMN unit VARCHAR(32);
  END IF;
  IF NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'tc_alert_events' AND column_name = 'address') THEN
    ALTER TABLE tc_alert_events ADD COLUMN address VARCHAR(512);
  END IF;
  IF NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'tc_alert_events' AND column_name = 'geofenceid') THEN
    ALTER TABLE tc_alert_events ADD COLUMN geofenceid INT;
  END IF;
  IF NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'tc_alert_events' AND column_name = 'groupid') THEN
    ALTER TABLE tc_alert_events ADD COLUMN groupid INT;
  END IF;
  IF NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'tc_alert_events' AND column_name = 'attributes') THEN
    ALTER TABLE tc_alert_events ADD COLUMN attributes VARCHAR(4000);
  END IF;
END $$;
